{ pkgs, ... }:
{
  # Tools that already have their own home-manager modules are pulled in here
  # so importing nvim is enough to get its plugin dependencies.
  imports = [
    ../nodejs
    ../vale
  ];

  home.packages = with pkgs; [
    neovim
    # Required for lazy.nvim to clone plugins.
    git
    lazygit

    # Formatters used by conform.nvim (lua/plugins/conform.lua).
    rustfmt
    djlint
    ktlint
    phpPackages.php-cs-fixer
    # stylua, gofumpt, ruff, nixfmt and clang-tools are still sourced from
    # config/packages-user.nix until per-language modules exist.

    # LSPs configured in lua/plugins/nvim-lspconfig.lua.
    rust-analyzer
    phpactor
    terraform-ls
    regols
    gopls
    ruff
    pyright
    nixd

    ripgrep # needed for telescope
  ];

  xdg.configFile = {
    "nvim/init.lua".source = ./init.lua;
    "nvim/stylua.toml".source = ./stylua.toml;
    "nvim/lua/config".source = ./lua/config;
    "nvim/lua/misc".source = ./lua/misc;
    "nvim/lua/plugins".source = ./lua/plugins;
  };
}

-- Bootstrap lazy.nvim
local lazypath = vim.fn.stdpath("data") .. "/lazy/lazy.nvim"
if not (vim.uv or vim.loop).fs_stat(lazypath) then
	local lazyrepo = "https://github.com/folke/lazy.nvim.git"
	local out = vim.fn.system({ "git", "clone", "--filter=blob:none", "--branch=stable", lazyrepo, lazypath })
	if vim.v.shell_error ~= 0 then
		vim.api.nvim_echo({
			{ "Failed to clone lazy.nvim:\n", "ErrorMsg" },
			{ out, "WarningMsg" },
			{ "\nPress any key to exit..." },
		}, true, {})
		vim.fn.getchar()
		os.exit(1)
	end
end
vim.opt.rtp:prepend(lazypath)

-- Setup lazy.nvim
require("lazy").setup({
	-- File explorer
	{
		"preservim/nerdtree",
		cmd = { "NERDTree", "NERDTreeToggle", "NERDTreeFind" },
		keys = {
			{ "<leader>e", "<cmd>:e .<cr>", desc = "Open NERDTree" },
		},
		init = function()
			-- Load NERDTree when opening a directory
			vim.api.nvim_create_autocmd("BufEnter", {
				pattern = "*",
				callback = function()
					if vim.fn.isdirectory(vim.fn.expand("%:p")) == 1 then
						require("lazy").load({ plugins = { "nerdtree" } })
					end
				end,
			})
		end,
		config = function()
			vim.g.NERDTreeQuitOnOpen = 1
			vim.g.NERDTreeShowHidden = 1
			-- Hide Python cache and build files
			vim.g.NERDTreeIgnore = {
				"__pycache__",
				"\\.pyc$",
				"\\.pyo$",
				"\\.pyd$",
				"\\.pytest_cache$",
				"\\.mypy_cache$",
				"\\.ruff_cache$",
			}
		end,
	},

	-- Buffer explorer
	{
		"jlanzarotta/bufexplorer",
		keys = {
			{ "<leader>w", "<cmd>BufExplorer<cr>", desc = "Buffer Explorer" },
		},
	},

	-- Window tabs
	{
		"zefei/vim-wintabs",
		event = "VeryLazy",
		config = function()
			require("plugins/vim-wintabs")
		end,
	},

