		ft = { "graphql", "gql" },
	},

	-- Twig syntax
	{
		"nelsyeung/twig.vim",
		ft = { "twig" },
	},

	-- Augment Code
	{
		"augmentcode/augment.vim",
		event = "VeryLazy",
		config = function()
			require("plugins/augment-code")
		end,
	},

	-- Color scheme
